const current = $('SELECT draft atual').first().json;
const wh = $('Webhook Regenerar').item.json.body || {};
const reviewerNotes = wh.reviewer_notes || '';
const pillar = current.pillar;
const SYSTEM = 'Voce e um redator medico brasileiro especializado em gastroenterologia, endoscopia digestiva, colonoscopia, hepatologia e geriatria. Escreve para pacientes leigos em PT-BR claro, com revisao CFM. SEMPRE emite o resultado chamando a ferramenta emit_post (objeto BlogPost estruturado, sem texto fora da ferramenta). Inclui ao menos 3 H2, ao menos 1500 palavras, FAQ com 4-6 perguntas, autoria Dra. Jane Erika Frazao Okazaki (CRM-PE 19872, RQE 17633). Sem promessas de cura, sem before-after, sem testimonials.';
const SCHEMA = 'SCHEMA EXATO DOS BLOCKS (use os nomes EXATOS dos campos): { type: "p", text: "..." } | { type: "h3", text: "..." } | { type: "ul", items: ["item1", "item2"] } | { type: "callout", text: "..." } | { type: "warning", text: "..." } | { type: "inline-cta", label: "...", text: "..." } | { type: "link", label: "...", href: "/..." } | { type: "video", youtubeId: "...", caption: "..." }. NUNCA use os campos "content", "body", "value" ou "heading" — apenas "text", "items", "label", "href", "youtubeId", "caption". Cada section: { id: "slug-style", h2: "Titulo", blocks: [...] }. Cada faq: { q: "pergunta", a: "resposta" }.';
const USER = 'Regenere um post de blog medico aplicando OBRIGATORIAMENTE estas mudancas solicitadas pela revisora: ' + reviewerNotes + '\n\nPilar: ' + pillar + '. Versao atual (use como ponto de partida e melhore conforme as mudancas): ' + JSON.stringify(current.content_json).slice(0, 8000) + '\n\n' + SCHEMA + '\n\nEmita via ferramenta emit_post um objeto com este shape: { slug, pillar, title, description (140-160 chars com geo-modifier em Recife), keywords, h1, lead, eyebrow (BLOG dot ' + String(pillar).toUpperCase() + '), breadcrumbLabel, about, excerpt (80-200 chars), sections, faqs, author (Dra. Jane Erika Frazao Okazaki, CRM-PE 19872, RQE 17633, photo /assets/team/jane.webp, bio), publishedAt ISO, updatedAt ISO }. Total 1500-2000 palavras em 4-6 sections com 3+ blocks cada. Inclua ao menos 1 link interno para /' + pillar + '.';
return [{ json: { draft_id: current.id, pillar, system: SYSTEM, user: USER } }];

const raw = $input.item.json;
const tu = (raw.content || []).find(c => c.type === 'tool_use');
if (!tu || !tu.input) throw new Error('Anthropic response sem tool_use. stop_reason=' + (raw.stop_reason || '?'));
const parsed = tu.input;
const required = ['slug','pillar','title','description','keywords','h1','lead','eyebrow','breadcrumbLabel','about','excerpt','sections','faqs','author','publishedAt','updatedAt'];
const missing = required.filter(k => !(k in parsed));
if (missing.length) throw new Error('Campos faltando: ' + missing.join(','));
if (!Array.isArray(parsed.sections) || parsed.sections.length === 0) throw new Error('sections vazio');
if (!Array.isArray(parsed.faqs)) throw new Error('faqs deve ser array');
if (!/^[a-z0-9][a-z0-9-]*$/.test(parsed.slug)) throw new Error('slug invalido: ' + parsed.slug);
if (parsed.description.length < 80 || parsed.description.length > 200) throw new Error('description fora de 80-200 chars: ' + parsed.description.length);
const flatText = JSON.stringify(parsed);
const wordCount = flatText.split(/\s+/).length;
const keywordsArr = typeof parsed.keywords === 'string' ? parsed.keywords.split(',').map(k => k.trim()) : parsed.keywords;
const draft_id = $('Montar Prompt Regenerar').item.json.draft_id;
return { json: { draft_id, slug: parsed.slug, pillar: parsed.pillar, title: parsed.title, meta_description: parsed.description, keywords: keywordsArr, content_json: parsed, word_count: wordCount } };
